from typing import List, Dict, Any, Optional
from leann.cli import LeannCLI
from leann.api import LeannBuilder, LeannSearcher
from pathlib import Path

def convert_cli_args_to_api_config(
    args_list: List[str],
    command_type: str = "build"
) -> Dict[str, Any]:
    """Convert CLI arguments to API configuration dictionary.

    Args:
        args_list: List of command line arguments
        command_type: Type of command ('build' or 'search')

    Returns:
        Dictionary containing API configuration extracted from CLI arguments
    """
    # Create CLI instance and parser
    cli = LeannCLI()
    parser = cli.create_parser()

    # Prepend command type to args list for proper parsing
    full_args = [command_type] + args_list
    parsed_args = parser.parse_args(full_args)

    # Initialize base configuration
    config = {}

    # Extract common parameters
    if hasattr(parsed_args, 'index') and parsed_args.index:
        config['index_path'] = str(parsed_args.index)

    if hasattr(parsed_args, 'backend') and parsed_args.backend:
        config['backend'] = parsed_args.backend

    if hasattr(parsed_args, 'llm') and parsed_args.llm:
        config['llm_config'] = parsed_args.llm

    # Extract command-specific parameters
    if command_type == "build":
        if hasattr(parsed_args, 'docs') and parsed_args.docs:
            config['docs_paths'] = [str(doc) for doc in parsed_args.docs]

        # Build-specific parameters
        if hasattr(parsed_args, 'chunk_size') and parsed_args.chunk_size:
            config['chunk_size'] = parsed_args.chunk_size

        if hasattr(parsed_args, 'chunk_overlap') and parsed_args.chunk_overlap:
            config['chunk_overlap'] = parsed_args.chunk_overlap

    elif command_type == "search":
        if hasattr(parsed_args, 'query') and parsed_args.query:
            config['query'] = parsed_args.query

        # Search-specific parameters
        if hasattr(parsed_args, 'top_k') and parsed_args.top_k:
            config['top_k'] = parsed_args.top_k

        if hasattr(parsed_args, 'metadata_filters') and parsed_args.metadata_filters:
            config['metadata_filters'] = parsed_args.metadata_filters

        if hasattr(parsed_args, 'port') and parsed_args.port:
            config['port'] = parsed_args.port

    # Extract verbosity if present
    if hasattr(parsed_args, 'verbose') and parsed_args.verbose:
        config['verbose'] = parsed_args.verbose

    # Extract model configuration if present
    if hasattr(parsed_args, 'model') and parsed_args.model:
        if 'llm_config' not in config:
            config['llm_config'] = {}
        config['llm_config']['model'] = parsed_args.model

    # Extract API key configuration if present
    if hasattr(parsed_args, 'api_key') and parsed_args.api_key:
        if 'llm_config' not in config:
            config['llm_config'] = {}
        config['llm_config']['api_key'] = parsed_args.api_key

    return config

